import{_ as a,o,c as t,ae as i}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Oracle Bronto Configuration","description":"","frontmatter":{"title":"Oracle Bronto Configuration","slug":"oracle-bronto-configuration"},"headers":[],"relativePath":"developer-hub/oracle-bronto-configuration.md","filePath":"developer-hub/oracle-bronto-configuration.md"}'),n={name:"developer-hub/oracle-bronto-configuration.md"};function r(l,e,s,c,d,h){return o(),t("div",null,[...e[0]||(e[0]=[i('<p><em>[Image: 1328]</em></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Marketing Tools for High-Growth Retailers. Sophisticated commerce marketing automation for increased engagement to maximize revenue opportunities.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li><p>User clicks on a link in an email from their mobile mail client (Gmail, Apple Mail, etc.)</p></li><li><p>If the user has the app installed and the link has a corresponding screen in the app, the app will open and deep link the user to the right content.</p><ul><li>Ex. Product detail page, category shopping page, etc.</li></ul></li><li><p>If the user does not have the app installed or the link only corresponds to a screen on the web, the user is routed to the website using their default mobile web browser.</p><ul><li>Ex. Unsubscribe link, privacy policy, etc.</li></ul></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Required Roles</p><p>Branch&#39;s Branch Email requires the following roles involved in order to enable:</p><ul><li>Developers</li><li>CRM/Email Team</li><li>Oracle Bronto Account Manager / Support Team</li></ul></div><p>In order to enable Bronto, you must first:</p><ol><li><p>Have admin access to your <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Have Branch&#39;s Engagement <a href="./packaging.html">product</a> enabled for your Branch Account.</p></li><li><p>Implement the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><p>Set Up Deep Link Routing. How your mobile app routes to in-app content will determine how you will create and tag your Branch Links.</p><ul><li><a href="./in-app-routing.html#option-1-build-custom-routing-inside-the-routing-callback">Build custom routing inside the routing callback</a></li><li><a href="./in-app-routing.html#option-2-let-branch-use-your-existing-deep-link-routing">Let Branch use your existing deep link routing</a></li></ul></li><li><p><a href="./track-branch-events.html">Track events</a></p></li></ul></li><li><p>Review our <a href="./email-overview.html">Email Overview</a> and <a href="./email-integration-guide.html">Basic Email Integration Guide</a> to understand the feature and our integrations.</p></li><li><p>Obtain or set up your Bronto <strong>click tracking domain</strong> (CTD). Reach out to your Bronto account manager for assistance on this.</p></li></ol><h2 id="enable-oracle-bronto" tabindex="-1">Enable Oracle Bronto <a class="header-anchor" href="#enable-oracle-bronto" aria-label="Permalink to &quot;Enable Oracle Bronto&quot;">​</a></h2><h2 id="connect-oracle-bronto-service-in-branch" tabindex="-1">Connect Oracle Bronto Service in Branch <a class="header-anchor" href="#connect-oracle-bronto-service-in-branch" aria-label="Permalink to &quot;Connect Oracle Bronto Service in Branch&quot;">​</a></h2><p>In the Branch Dashboard in Email → <a href="https://dashboard.branch.io/email/manager" target="_blank" rel="noreferrer">Manager tab</a>, find <strong>Oracle Bronto</strong> and click <strong>Enable</strong></p><p><em>[Image: 1428]</em></p><h3 id="input-click-tracking-domain" tabindex="-1">Input Click Tracking Domain <a class="header-anchor" href="#input-click-tracking-domain" aria-label="Permalink to &quot;Input Click Tracking Domain&quot;">​</a></h3><p>Click tracking domains allow you to track engagement on email opens and link clicks.</p><p>The Oracle Bronto integration requires you provide the following:</p><ul><li><strong>Click Tracking Domain</strong> - The domain you use with Oracle Bronto for links in emails</li></ul><p>For additional help, please see Oracle Bronto&#39;s <a href="https://helpdocs.bronto.com/bmp/task/t_bmp_home_data_exchange_link_tracking_set_up.html" target="_blank" rel="noreferrer">documentation</a>.</p><div class="warning custom-block"><p class="custom-block-title">Click Tracking Domain</p><ul><li>Remove <code>https://</code> when adding your click tracking domain.</li><li>Never add the same CTD to both your <strong>Live</strong> and <strong>Test</strong> Branch environments.</li><li>You can enable the integration with multiple CTDs, if needed, but you <strong>cannot</strong> add the same CTD to multiple Branch Dashboards or ESP integrations.</li></ul></div><h2 id="configure-your-app" tabindex="-1">Configure your App <a class="header-anchor" href="#configure-your-app" aria-label="Permalink to &quot;Configure your App&quot;">​</a></h2><h3 id="add-your-bronto-ctd-to-your-associated-domains" tabindex="-1">Add your Bronto CTD to your Associated Domains <a class="header-anchor" href="#add-your-bronto-ctd-to-your-associated-domains" aria-label="Permalink to &quot;Add your Bronto CTD to your Associated Domains&quot;">​</a></h3><p>For your iOS App, you must add the CTD to the Associated Domains. Additional details can be found <a href="./ios-basic-integration.html#3-configure-associated-domains">here</a>.</p><p>.png &quot;Associated Domains.png&quot;)</p><h3 id="return-yes-to-continueuseractivity" tabindex="-1">Return <code>YES</code> to <code>continueUserActivity</code> <a class="header-anchor" href="#return-yes-to-continueuseractivity" aria-label="Permalink to &quot;Return `YES` to `continueUserActivity`&quot;">​</a></h3><p>Additionally, you will need to add the CTD to your iOS app&#39;s info.plist file. Additional details can be found <a href="./ios-advanced-features.html#return-yes-to-continueuseractivity">here</a>.</p><p>.png &quot;branch-universal-link-domain.png&quot;)</p><h2 id="point-dns-cname-to-branch" tabindex="-1">Point DNS CNAME to Branch <a class="header-anchor" href="#point-dns-cname-to-branch" aria-label="Permalink to &quot;Point DNS CNAME to Branch&quot;">​</a></h2><p>Please follow your web hosting provider’s instructions on how to configure your DNS CNAME.</p><p>Update the DNS CNAME and point it to <code>thirdparty.bnc.lt</code>. Once the CNAME record is added, please allow up to an hour for Branch to generate SSL and AASA files for your click tracking domain.</p><p><strong>Important CNAME Info</strong></p><ul><li>The Branch dashboard must be enabled &amp; reflect the CTD <strong>BEFORE</strong> you add the CNAME.</li><li>If the CTD already has SSL setup, confirm if your security credentials allow a 3rd party to submit a CSR on behalf of the domain. If not, contact Branch&#39;s Support team, to coordinate providing an SSL certificate manually to Branch.</li><li>Once the CNAME is added, Branch auto-generates an SSL certificate and AASA file for your click tracking domain. It may take up to an hour to resolve SSL errors once you change the CNAME. During this time, link redirects on the click tracking domain will redirect to the <strong>Default URL</strong> you provided in the <strong>General Configuration</strong> section of your account.</li><li>If you are making this change to a live domain with active email click traffic, schedule the CNAME change to occur during an off-hours time with low click traffic.</li></ul><h2 id="add-branch-links-to-your-emails" tabindex="-1">Add Branch Links to your Emails <a class="header-anchor" href="#add-branch-links-to-your-emails" aria-label="Permalink to &quot;Add Branch Links to your Emails&quot;">​</a></h2><p>Before you start sending your email campaigns, you need to determine what flow you want the user to experience and flag your email links accordingly.</p><h3 id="add-deep-linking-flag" tabindex="-1">Add Deep Linking Flag <a class="header-anchor" href="#add-deep-linking-flag" aria-label="Permalink to &quot;Add Deep Linking Flag&quot;">​</a></h3><p>For the email links that you would like to deep link to content, add <code>deeplink=&quot;true&quot;</code> to the HTML as a query parameter, for example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;a href=&quot;https://app.com&quot; deeplink=&quot;true&quot;&gt;Download the App!&lt;/a&gt;</span></span></code></pre></div><p>This will ensure that your links are converted to Branch Links that will open the app on iOS and Android, with full tracking and attribution.</p><p><strong>Analytics on the Branch Dashboard</strong></p><p>To see how the email campaigns have performed and break it down into campaigns, it is very essential to tag your email links with the ~campaign tag. If your team uses UTM tags, Branch will also ingest the UTM_campaign tag. This will help dedupe the numbers and hence see the downstream events. You can add the campaign tag in any comparisons and filters in any Dashboard views.</p>',39)])])}const m=a(n,[["render",r]]);export{p as __pageData,m as default};
